import java.io.IOException;
import javax.servlet.ServletException;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class XSSFixedServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response)
            throws ServletException, IOException {
        String userInput = request.getParameter("input");
        String sanitizedInput = sanitizeInput(userInput);

        response.setContentType("text/html");
        response.getWriter().println("Sanitized user input: " + sanitizedInput);
    }

    private String sanitizeInput(String input) {
        // Implement proper input sanitization to prevent XSS attacks
        // For example, you can use OWASP Java HTML Sanitizer or escape HTML special characters

        // Here is a simple example of escaping HTML special characters
        return input.replaceAll("&", "&amp;")
                     .replaceAll("<", "&lt;")
                     .replaceAll(">", "&gt;")
                     .replaceAll("\"", "&quot;")
                     .replaceAll("'", "&#39;");
    }
}

